    def tearDown(self):
        for suffix in ("", "-wal", "-shm"):
            db_file = self.db_path + suffix
            if os.path.exists(db_file):
                os.remove(db_file)
        if os.path.isdir(self.photo_upload_root):
            shutil.rmtree(self.photo_upload_root)
        if os.path.isdir(self.daily_report_upload_root):
            shutil.rmtree(self.daily_report_upload_root)
        if os.path.isdir(self.document_upload_root):
            shutil.rmtree(self.document_upload_root)
        if os.path.isdir(self.document_signature_root):
            shutil.rmtree(self.document_signature_root)
        if os.path.isdir(self.receipt_pdf_root):
            shutil.rmtree(self.receipt_pdf_root)
        if os.path.isdir(self.ipos4_runtime_root):
            shutil.rmtree(self.ipos4_runtime_root)
        if os.path.isdir(self.sms_storage_root):
            shutil.rmtree(self.sms_storage_root)
        if os.path.isdir(self.sms_storage_data_root):
            shutil.rmtree(self.sms_storage_data_root)

    def test_database_translation_replaces_qmark_and_datetime_now(self):
        translated = _translate_sqlite_query_to_postgres(
            "UPDATE approvals SET approved_at=datetime('now') WHERE id=? AND note <> '?'"
        )
        self.assertIn("CURRENT_TIMESTAMP", translated)
        self.assertIn("id=%s", translated)
        self.assertIn("'?'", translated)

    def test_database_translation_supports_date_modifier(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT * FROM stock WHERE date(updated_at) <= date('now', '+30 day')"
        )
        self.assertIn("CAST(updated_at AS date)", translated)
        self.assertIn("INTERVAL '+30 day'", translated)

    def test_database_translation_supports_begin_immediate_and_datetime_expr(self):
        translated = _translate_sqlite_query_to_postgres(
            'BEGIN IMMEDIATE; SELECT * FROM stock_batches ORDER BY datetime(created_at) ASC'
        )
        self.assertIn("BEGIN; SELECT", translated)
        self.assertIn("CAST(created_at AS timestamp)", translated)

    def test_database_translation_supports_double_quote_now_syntax(self):
        translated = _translate_sqlite_query_to_postgres(
            'SELECT * FROM password_resets WHERE expires_at > datetime("now")'
        )
        self.assertIn("CURRENT_TIMESTAMP", translated)

    def test_database_translation_supports_datetime_modifier_on_expression(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT * FROM audit WHERE datetime(h.date, '+7 hours') IS NOT NULL"
        )
        self.assertIn("CAST(h.date AS timestamp)", translated)
        self.assertIn("INTERVAL '+7 hours'", translated)

    def test_database_translation_supports_parameterized_datetime_modifier(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT * FROM chat_call_sessions WHERE COALESCE(last_signal_at, started_at) <= datetime('now', ?)"
        )
        self.assertIn("CURRENT_TIMESTAMP", translated)
        self.assertIn("CAST(%s AS interval)", translated)

    def test_database_translation_supports_nested_date_expression(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT * FROM stock WHERE date(substr(expiry_date, 1, 10)) <= date('now', '+30 day')"
        )
        self.assertIn("CAST(substr(expiry_date, 1, 10) AS date)", translated)
        self.assertIn("CURRENT_DATE", translated)

    def test_database_translation_supports_julianday_math(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT CAST((julianday('now') - julianday(created_at)) AS INTEGER) as age FROM stock_batches"
        )
        self.assertIn("EXTRACT(EPOCH FROM CURRENT_TIMESTAMP)", translated)
        self.assertIn("EXTRACT(EPOCH FROM CAST(created_at AS timestamp))", translated)

    def test_database_translation_supports_strftime_weekday(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT strftime('%w', created_at) as day FROM stock_movements"
        )
        self.assertIn("EXTRACT(DOW FROM CAST(created_at AS timestamp))", translated)

    def test_database_translation_supports_insert_or_ignore(self):
        translated = _translate_sqlite_query_to_postgres(
            "INSERT OR IGNORE INTO chat_thread_members(thread_id, user_id) VALUES (?, ?)"
        )
        self.assertIn("INSERT INTO chat_thread_members", translated)
        self.assertIn("VALUES (%s, %s) ON CONFLICT DO NOTHING", translated)

    def test_database_translation_converts_like_to_ilike(self):
        translated = _replace_like_operators(
            "SELECT * FROM products WHERE name LIKE ? AND sku NOT LIKE ? AND note <> 'LIKE ?'"
        )
        self.assertIn("name ILIKE ?", translated)
        self.assertIn("sku NOT ILIKE ?", translated)
        self.assertIn("'LIKE ?'", translated)

    def test_database_translation_removes_collate_nocase(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT * FROM products ORDER BY name COLLATE NOCASE ASC, variant COLLATE NOCASE DESC"
        )
        self.assertNotIn("COLLATE NOCASE", translated.upper())
        self.assertIn("ORDER BY name ASC, variant DESC", translated)

    def test_database_translation_supports_group_concat(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT GROUP_CONCAT(DISTINCT p.name || ' / ' || v.variant, ' | ') AS items_summary FROM crm_purchase_items"
        )
        self.assertIn("STRING_AGG(DISTINCT p.name || ' / ' || v.variant, ' | ')", translated)

    def test_database_translation_supports_substr_on_timestamp_columns(self):
        translated = _translate_sqlite_query_to_postgres(
            "SELECT * FROM stock WHERE date(substr(expiry_date, 1, 10)) <= date('now', '+30 day')"
        )
        self.assertIn("SUBSTRING(CAST(expiry_date AS text) FROM 1 FOR 10)", translated)
        self.assertIn("CAST(SUBSTRING(CAST(expiry_date AS text) FROM 1 FOR 10) AS date)", translated)

    def test_attendance_portal_datetime_helpers_accept_datetime_objects(self):
        sample = datetime(2026, 4, 15, 8, 45, 0)
        self.assertEqual(_format_portal_datetime_display(sample), "08:45")
        self.assertEqual(_format_portal_datetime_display(sample, include_date=True), "15 Apr 2026 08:45")
        self.assertEqual(_parse_attendance_portal_datetime(sample), sample)

    def test_announcement_date_helpers_accept_datetime_objects(self):
        sample = datetime(2026, 4, 15, 9, 30, 0)
        self.assertEqual(parse_iso_date(sample), sample.date())
        self.assertEqual(_extract_iso_date_prefix(sample), "2026-04-15")

    def test_hris_datetime_helpers_accept_datetime_objects(self):
        sample = datetime(2026, 4, 15, 14, 5, 0)
        self.assertEqual(_format_hris_datetime_display(sample), "14:05")
        self.assertEqual(_format_hris_datetime_display(sample, include_date=True), "15/04/2026 14:05")
        self.assertEqual(_normalize_datetime_input(sample), "2026-04-15 14:05:00")
        self.assertEqual(_normalize_time_of_day_input(sample), "14:05")

    def test_create_app_skips_sqlite_init_when_postgresql_backend_selected(self):
        original_backend = Config.DATABASE_BACKEND
        original_url = Config.DATABASE_URL
        Config.DATABASE_BACKEND = "postgresql"
        Config.DATABASE_URL = "postgresql://user:pass@127.0.0.1:5432/erp_test"
        try:
            with patch("app.init_db") as mocked_init_db, patch("app.ensure_super_admin"), patch("app.repair_restored_data"):
                postgres_app = create_app()
            self.assertEqual(postgres_app.config["DATABASE_BACKEND"], "postgresql")
            mocked_init_db.assert_not_called()
        finally:
            Config.DATABASE_BACKEND = original_backend
            Config.DATABASE_URL = original_url

    def test_run_configured_backup_keeps_service_start_non_fatal_for_postgresql_backup_error(self):
        original_backend = run_configured_backup_module.Config.DATABASE_BACKEND
        original_url = run_configured_backup_module.Config.DATABASE_URL
        run_configured_backup_module.Config.DATABASE_BACKEND = "postgresql"
        run_configured_backup_module.Config.DATABASE_URL = "postgresql://user:pass@127.0.0.1:5432/erp_test"
        try:
            with patch.object(
                run_configured_backup_module,
                "parse_args",
                return_value=Mock(output_dir=self.receipt_pdf_root, retain_days=14),
            ), patch.object(
                run_configured_backup_module,
                "backup_postgresql_database",
                side_effect=RuntimeError("pg_dump failed"),
            ), patch.object(run_configured_backup_module, "print_postgresql_step") as mocked_step:
                result = run_configured_backup_module.main()

            self.assertEqual(result, 0)
            mocked_step.assert_any_call("Backup gagal dijalankan: pg_dump failed")
            mocked_step.assert_any_call("Startup service tetap dilanjutkan tanpa menghentikan aplikasi.")
        finally:
            run_configured_backup_module.Config.DATABASE_BACKEND = original_backend
            run_configured_backup_module.Config.DATABASE_URL = original_url

    def test_postgresql_smoke_test_reports_missing_career_tables_cleanly(self):
        original_backend = postgresql_smoke_test_module.Config.DATABASE_BACKEND
        original_url = postgresql_smoke_test_module.Config.DATABASE_URL
        postgresql_smoke_test_module.Config.DATABASE_BACKEND = "postgresql"
        postgresql_smoke_test_module.Config.DATABASE_URL = "postgresql://user:pass@127.0.0.1:5432/erp_test"

        class FakeCursor:
            def __init__(self):
                self.last_query = ""
                self.last_params = ()

            def __enter__(self):
                return self

            def __exit__(self, exc_type, exc, tb):
                return False

            def execute(self, query, params=None):
                self.last_query = str(query)
                self.last_params = params or ()

            def fetchone(self):
                if "to_regclass" in self.last_query:
                    table_name = str(self.last_params[0]).split(".", 1)[-1]
                    existing_tables = {
                        "products",
                        "product_variants",
                        "stock",
                        "users",
                        "warehouses",
                        "requests",
                        "stock_movements",
                        "attendance_action_requests",
                        "overtime_usage_records",
                        "overtime_balance_adjustments",
                        "career_openings",
                    }
                    return (f"public.{table_name}",) if table_name in existing_tables else (None,)
                if "COUNT(*) FROM warehouses" in self.last_query:
                    return (2,)
                if "COUNT(*) FROM career_openings" in self.last_query:
                    return (4,)
                if "COUNT(*) FROM requests WHERE status = 'pending'" in self.last_query:
                    return (3,)
                if "information_schema.columns" in self.last_query:
                    if "recruitment_candidates" in self.last_query:
                        return (0,)
                    return (1,)
                if "pg_indexes" in self.last_query:
                    return (0,)
                return (1,)

        class FakeConnection:
            def __enter__(self):
                return self

            def __exit__(self, exc_type, exc, tb):
                return False

            def cursor(self):
                return FakeCursor()

        try:
            fake_psycopg = Mock(connect=Mock(return_value=FakeConnection()))
            with patch.object(postgresql_smoke_test_module, "psycopg", fake_psycopg), patch(
                "sys.stdout",
                new_callable=StringIO,
            ) as stdout:
                result = postgresql_smoke_test_module.main()

            self.assertEqual(result, 0)
            payload = json.loads(stdout.getvalue())
            self.assertEqual(payload["status"], "incomplete")
            self.assertIn("recruitment_candidates", payload["missing_tables"])
            self.assertIn("recruitment_assessment_questions", payload["missing_tables"])
            self.assertIn("career_public_account_requests", payload["missing_tables"])
            self.assertTrue(payload["tables"]["career_openings"]["exists"])
            self.assertEqual(payload["tables"]["career_openings"]["row_count"], 4)
            self.assertFalse(payload["schema_checks"]["recruitment_candidates.application_channel"])
            self.assertFalse(payload["schema_checks"]["idx_recruitment_candidates_public_lookup"])
        finally:
            postgresql_smoke_test_module.Config.DATABASE_BACKEND = original_backend
            postgresql_smoke_test_module.Config.DATABASE_URL = original_url

