    def create_overtime_add_request_record(
        self,
        employee_id,
        request_date,
        minutes_delta,
        *,
        status="approved",
        source_type="manual_request",
        note=None,
        requested_by=None,
        handled_by=None,
        create_adjustment=False,
    ):
        with self.app.app_context():
            db = get_db()
            employee = db.execute(
                "SELECT id, full_name, warehouse_id FROM employees WHERE id=?",
                (employee_id,),
            ).fetchone()
            self.assertIsNotNone(employee)
            employee = dict(employee)

            note_text = note or (
                f"Lembur otomatis {request_date}"
                if source_type == "biometric_auto"
                else f"Tambah lembur manual {request_date}"
            )
            payload = {
                "source_type": source_type,
                "employee_id": employee["id"],
                "employee_name": employee["full_name"],
                "warehouse_id": employee["warehouse_id"],
                "attendance_date": request_date,
                "adjustment_date": request_date,
                "minutes_delta": minutes_delta,
                "note": note_text,
            }
            if source_type == "biometric_auto":
                payload["breakdown_label"] = note_text

            handled_at = datetime.now().strftime("%Y-%m-%d %H:%M:%S") if status in {"approved", "rejected"} else None
            decision_note = (
                "Seed approved overtime request."
                if status == "approved"
                else "Seed rejected overtime request."
                if status == "rejected"
                else None
            )
            cursor = db.execute(
                """
                INSERT INTO attendance_action_requests(
                    request_type,
                    warehouse_id,
                    employee_id,
                    summary_title,
                    summary_note,
                    payload,
                    status,
                    requested_by,
                    handled_by,
                    handled_at,
                    decision_note,
                    updated_at
                )
                VALUES (?,?,?,?,?,?,?,?,?,?,?,?)
                """,
                (
                    "overtime_add",
                    employee["warehouse_id"],
                    employee["id"],
                    f"{employee['full_name']} - {'Lembur Otomatis' if source_type == 'biometric_auto' else 'Tambah Lembur'}",
                    note_text,
                    json.dumps(payload, sort_keys=True, ensure_ascii=True),
                    status,
                    requested_by,
                    handled_by,
                    handled_at,
                    decision_note,
                    datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                ),
            )
            request_id = cursor.lastrowid

            if create_adjustment and status == "approved":
                db.execute(
                    """
                    INSERT INTO overtime_balance_adjustments(
                        employee_id,
                        warehouse_id,
                        adjustment_date,
                        minutes_delta,
                        note,
                        handled_by,
                        updated_at
                    )
                    VALUES (?,?,?,?,?,?,?)
                    """,
                    (
                        employee["id"],
                        employee["warehouse_id"],
                        request_date,
                        minutes_delta,
                        note_text,
                        handled_by,
                        datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                    ),
                )
            db.commit()
        return request_id

    def create_product(self, sku=None, qty=5, variants="M,L", warehouse_id="1", name="Produk Uji"):
        sku = sku or ("AUTO-" + uuid4().hex[:8].upper())
        product_name = name if name != "Produk Uji" else f"Produk Uji {sku}"
        variant_names = [item.strip() for item in str(variants or "").split(",") if item.strip()] or ["default"]
        variant_mode = "variant" if len(variant_names) > 1 or variant_names[0] != "default" else "non_variant"

        with self.app.app_context():
            db = get_db()
            _ensure_product_variant_cost_schema(db)
            category_row = db.execute(
                "SELECT id FROM categories WHERE name=?",
                ("Testing",),
            ).fetchone()
            if category_row:
                category_id = category_row["id"]
            else:
                category_id = db.execute(
                    "INSERT INTO categories(name) VALUES (?)",
                    ("Testing",),
                ).lastrowid

            product_id = db.execute(
                """
                INSERT INTO products (sku, name, category_id, unit_label, variant_mode)
                VALUES (?, ?, ?, ?, ?)
                """,
                (sku, product_name, category_id, "pcs", variant_mode),
            ).lastrowid

            variants_rows = []
            for variant_name in variant_names:
                variant_id = db.execute(
                    """
                    INSERT INTO product_variants (
                        product_id, variant, price_retail, price_discount, price_nett, price_cost, variant_code, color, gtin, no_gtin
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (product_id, variant_name, 150000, 135000, 120000, 100000, "", "", "", 1),
                ).lastrowid
                stock_columns = {
                    str(row["name"])
                    for row in db.execute("PRAGMA table_info(stock)").fetchall()
                }
                if "expiry_date" in stock_columns:
                    db.execute(
                        "INSERT INTO stock (product_id, variant_id, warehouse_id, qty, expiry_date, created_at) VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP)",
                        (product_id, variant_id, int(warehouse_id), qty, None),
                    )
                elif "updated_at" in stock_columns:
                    db.execute(
                        "INSERT INTO stock (product_id, variant_id, warehouse_id, qty, updated_at) VALUES (?, ?, ?, ?, CURRENT_TIMESTAMP)",
                        (product_id, variant_id, int(warehouse_id), qty),
                    )
                else:
                    db.execute(
                        "INSERT INTO stock (product_id, variant_id, warehouse_id, qty) VALUES (?, ?, ?, ?)",
                        (product_id, variant_id, int(warehouse_id), qty),
                    )
                variants_rows.append({"id": variant_id, "variant": variant_name})

            db.commit()

        response = Mock(status_code=302)

        return response, product_id, variants_rows

