    def test_imported_ipos_sales_show_source_sales_name_when_user_mapping_is_missing(self):
        self.login_pos_user("pos_imported_ipos_super", "super_admin")
        receipt_no = "IPOS-45912-KSR-MTR-0426"

        with self.app.app_context():
            db = get_db()
            customer_id = db.execute(
                """
                INSERT INTO crm_customers(warehouse_id, customer_name, phone, customer_type)
                VALUES (1, 'UMUM', '', 'walk_in')
                """
            ).lastrowid
            purchase_id = db.execute(
                """
                INSERT INTO crm_purchase_records(
                    customer_id, member_id, warehouse_id, purchase_date, invoice_no, channel,
                    transaction_type, items_count, total_amount, note, handled_by, created_at, updated_at
                )
                VALUES (?,?,?,?,?,'store','purchase',?,?,?,NULL,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP)
                """,
                (
                    customer_id,
                    None,
                    1,
                    "2026-04-09 10:19:05",
                    "45912/KSR/MTR/0426",
                    1,
                    80000,
                    "Imported from iPOS4: 45912/KSR/MTR/0426 | source_type=KSR | source_sales=AFIF | source_cashier=YUNI",
                ),
            ).lastrowid
            db.execute(
                """
                INSERT INTO pos_sales(
                    purchase_id, customer_id, warehouse_id, cashier_user_id, sale_date, receipt_no,
                    source_cashier_name, source_sales_name, payment_method, total_items, subtotal_amount,
                    discount_type, discount_value, discount_amount, tax_type, tax_value, tax_amount,
                    total_amount, paid_amount, change_amount, status, note, created_at, updated_at
                )
                VALUES (
                    ?, ?, ?, NULL, ?, ?,
                    ?, ?, ?, ?, ?,
                    'amount', 0, 0, 'amount', 0, 0,
                    ?, ?, ?, 'posted', ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
                )
                """,
                (
                    purchase_id,
                    customer_id,
                    1,
                    "2026-04-09",
                    receipt_no,
                    "YUNI",
                    "AFIF",
                    "debit",
                    1,
                    80000,
                    80000,
                    80000,
                    0,
                    "Imported from iPOS4: 45912/KSR/MTR/0426 | source_type=KSR | source_sales=AFIF | source_cashier=YUNI",
                ),
            )
            db.commit()

        log_response = self.client.get("/kasir/log?warehouse=1&date_from=2026-04-09&date_to=2026-04-09&search=45912")
        self.assertEqual(log_response.status_code, 200)
        log_html = log_response.get_data(as_text=True)
        self.assertIn(receipt_no, log_html)
        self.assertIn("AFIF", log_html)
        self.assertNotIn("Tanpa Staff", log_html)

        print_response = self.client.get(f"/kasir/receipt/{receipt_no}/print")
        self.assertEqual(print_response.status_code, 200)
        print_html = print_response.get_data(as_text=True)
        self.assertIn("AFIF", print_html)
        self.assertIn(receipt_no, print_html)

    def test_imported_ipos_sales_reports_follow_source_sales_name_even_when_user_is_mapped(self):
        self.create_user("ipos_import_mapping_rio", "pass1234", "staff", warehouse_id=1)
        mapped_user_id = self.get_user_id("ipos_import_mapping_rio")
        self.login_pos_user("pos_imported_ipos_group_super", "super_admin")
        super_user_id = self.get_user_id("pos_imported_ipos_group_super")

        with self.app.app_context():
            db = get_db()
            for sequence, sales_name in enumerate(("AFIF", "NAUFAL"), start=1):
                customer_id = db.execute(
                    """
                    INSERT INTO crm_customers(warehouse_id, customer_name, phone, customer_type)
                    VALUES (?, ?, '', 'walk_in')
                    """,
                    (1, f"UMUM IPOS {sequence}"),
                ).lastrowid
                invoice_no = f"5591{sequence}/KSR/MTR/0426"
                receipt_no = f"IPOS-MAP-MTR-0426-{sequence}"
                purchase_id = db.execute(
                    """
                    INSERT INTO crm_purchase_records(
                        customer_id, member_id, warehouse_id, purchase_date, invoice_no, channel,
                        transaction_type, items_count, total_amount, note, handled_by, created_at, updated_at
                    )
                    VALUES (?,?,?,?,?,'store','purchase',?,?,?, ?,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP)
                    """,
                    (
                        customer_id,
                        None,
                        1,
                        "2026-04-27 10:19:05",
                        invoice_no,
                        1,
                        80000 + (sequence * 1000),
                        f"Imported from iPOS4: {invoice_no} | source_type=KSR | source_sales={sales_name} | source_cashier=RIO",
                        mapped_user_id,
                    ),
                ).lastrowid
                db.execute(
                    """
                    INSERT INTO pos_sales(
                        purchase_id, customer_id, warehouse_id, cashier_user_id, sale_date, receipt_no,
                        source_cashier_name, source_sales_name, payment_method, total_items, subtotal_amount,
                        discount_type, discount_value, discount_amount, tax_type, tax_value, tax_amount,
                        total_amount, paid_amount, change_amount, status, note, created_at, updated_at
                    )
                    VALUES (
                        ?, ?, ?, ?, ?, ?,
                        ?, ?, ?, ?, ?,
                        'amount', 0, 0, 'amount', 0, 0,
                        ?, ?, ?, 'posted', ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
                    )
                    """,
                    (
                        purchase_id,
                        customer_id,
                        1,
                        mapped_user_id,
                        "2026-04-27",
                        receipt_no,
                        "RIO",
                        sales_name,
                        "debit",
                        1,
                        80000 + (sequence * 1000),
                        80000 + (sequence * 1000),
                        80000 + (sequence * 1000),
                        0,
                        f"Imported from iPOS4: {invoice_no} | source_sales={sales_name}",
                    ),
                )
            db.commit()

            with self.app.test_request_context("/kasir/log?warehouse=1&date_from=2026-04-27&date_to=2026-04-27"):
                session["role"] = "super_admin"
                session["user_id"] = super_user_id
                session["warehouse_id"] = 1

                rows = _fetch_pos_sale_logs(
                    db,
                    "2026-04-27",
                    "2026-04-27",
                    selected_warehouse=1,
                    search_query="IPOS-MAP-MTR-0426",
                    limit=20,
                )
                mapped_rows = [row for row in rows if str(row.get("receipt_no", "")).startswith("IPOS-MAP-MTR-0426-")]
                self.assertEqual({row["cashier_name"] for row in mapped_rows}, {"AFIF", "NAUFAL"})

                summary = _build_pos_sale_log_summary(mapped_rows, "27 April 2026")
                self.assertEqual(summary["staff_total"], 2)

                report_rows = _fetch_pos_staff_sales_rows(
                    db,
                    "2026-04-27",
                    "2026-04-27",
                    selected_warehouse=1,
                )
                imported_report_names = {
                    row["staff_name"]
                    for row in report_rows
                    if row.get("staff_name") in {"AFIF", "NAUFAL"}
                }
                self.assertEqual(imported_report_names, {"AFIF", "NAUFAL"})

        log_response = self.client.get(
            "/kasir/log?warehouse=1&date_from=2026-04-27&date_to=2026-04-27&search=IPOS-MAP-MTR-0426"
        )
        self.assertEqual(log_response.status_code, 200)
        log_html = log_response.get_data(as_text=True)
        self.assertIn("AFIF", log_html)
        self.assertIn("NAUFAL", log_html)

        report_response = self.client.get("/kasir/staff-sales?warehouse=1&week_date=2026-04-27&month=2026-04")
        self.assertEqual(report_response.status_code, 200)
        report_html = report_response.get_data(as_text=True)
        self.assertIn("AFIF", report_html)
        self.assertIn("NAUFAL", report_html)

    def test_pos_checkout_generates_public_receipt_pdf_and_logs_failed_whatsapp_without_blocking_sale(self):
        self.create_user("staff_sales_kirimi", "pass1234", "staff", warehouse_id=1)
        selected_cashier_user_id = self.get_user_id("staff_sales_kirimi")
        self.login_pos_user("pos_kirimi_super", "super_admin")
        response, product_id, variants_rows = self.create_product(
            sku="POS-KIRIMI-001",
            qty=5,
            variants="42",
            warehouse_id="1",
        )
        self.assertEqual(response.status_code, 302)
        variant_id = variants_rows[0]["id"]

        with patch(
            "routes.pos.send_whatsapp_document",
            return_value={
                "ok": False,
                "provider": "kirimi",
                "receiver": "628120008888",
                "error": "kirimi_http_500",
            },
        ) as mocked_send:
            checkout = self.client.post(
                "/kasir/checkout",
                json={
                    "warehouse_id": 1,
                    "sale_date": "2026-04-03",
                    "cashier_user_id": selected_cashier_user_id,
                    "customer_name": "Customer Kirimi",
                    "customer_phone": "08120008888",
                    "payment_method": "cash",
                    "paid_amount": 151000,
                    "note": "Checkout kirimi",
                    "items": [
                        {
                            "product_id": product_id,
                            "variant_id": variant_id,
                            "qty": 1,
                            "unit_price": 150000,
                        }
                    ],
                },
                headers={"X-Requested-With": "XMLHttpRequest"},
            )

        self.assertEqual(checkout.status_code, 200)
        payload = checkout.get_json()
        self.assertEqual(payload["status"], "success")
        self.assertTrue(payload["receipt_pdf_public_url"].startswith("https://erp.test/static/test-pos-receipts/"))
        self.assertEqual(payload["receipt_whatsapp_status"], "failed")
        mocked_send.assert_called_once()

        with self.app.app_context():
            db = get_db()
            sale = db.execute(
                """
                SELECT
                    id,
                    receipt_pdf_path,
                    receipt_pdf_url,
                    receipt_whatsapp_status,
                    receipt_whatsapp_error
                FROM pos_sales
                WHERE receipt_no=?
                """,
                (payload["receipt_no"],),
            ).fetchone()
            notification = db.execute(
                """
                SELECT channel, recipient, subject, status, message
                FROM notifications
                WHERE subject=?
                ORDER BY id DESC
                LIMIT 1
                """,
                (f"Nota POS {payload['receipt_no']}",),
            ).fetchone()

        self.assertIsNotNone(sale)
        self.assertTrue(sale["receipt_pdf_path"])
        self.assertTrue(sale["receipt_pdf_url"].startswith("https://erp.test/static/test-pos-receipts/"))
        self.assertEqual(sale["receipt_whatsapp_status"], "failed")
        self.assertIn("kirimi_http_500", sale["receipt_whatsapp_error"])
        self.assertTrue(os.path.exists(os.path.join(self.receipt_pdf_root, sale["receipt_pdf_path"])))
        with open(os.path.join(self.receipt_pdf_root, sale["receipt_pdf_path"]), "rb") as file_handle:
            pdf_bytes = file_handle.read()
        self.assertTrue(pdf_bytes[:8].startswith(b"%PDF-1."))
        pdf_text = pdf_bytes.decode("latin-1", errors="ignore")
        self.assertIsNotNone(notification)
        self.assertEqual(notification["channel"], "wa_document")
        self.assertEqual(notification["recipient"], "628120008888")
        self.assertEqual(notification["status"], "failed")
        self.assertIn("kirimi_http_500", notification["message"])
        self.assertIn("Mataram Sports", pdf_text)
        self.assertIn("KASIR / SALES", pdf_text)
        self.assertIn("staff_sales_kirimi", pdf_text)
        self.assertIn("/Subtype /Image", pdf_text)
        self.assertIn("/DCTDecode", pdf_text)

    def test_pos_checkout_receipt_whatsapp_falls_back_to_text_link_when_document_send_fails(self):
        self.create_user("staff_sales_receipt_fallback", "pass1234", "staff", warehouse_id=1)
        selected_cashier_user_id = self.get_user_id("staff_sales_receipt_fallback")
        self.login_pos_user("pos_receipt_fallback_super", "super_admin")
        response, product_id, variants_rows = self.create_product(
            sku="POS-WA-FALLBACK-001",
            qty=5,
            variants="42",
            warehouse_id="1",
        )
        self.assertEqual(response.status_code, 302)
        variant_id = variants_rows[0]["id"]

        with patch(
            "routes.pos.send_whatsapp_document",
            return_value={
                "ok": False,
                "provider": "kirimi",
                "receiver": "628120006666",
                "error": "kirimi_http_500",
            },
        ) as mocked_document, patch(
            "routes.pos.send_whatsapp_text",
            return_value={
                "ok": True,
                "provider": "kirimi",
                "receiver": "628120006666",
                "error": "",
            },
        ) as mocked_text:
            checkout = self.client.post(
                "/kasir/checkout",
                json={
                    "warehouse_id": 1,
                    "sale_date": "2026-04-03",
                    "cashier_user_id": selected_cashier_user_id,
                    "customer_name": "Customer Fallback",
                    "customer_phone": "08120006666",
                    "payment_method": "cash",
                    "paid_amount": 151000,
                    "items": [
                        {
                            "product_id": product_id,
                            "variant_id": variant_id,
                            "qty": 1,
                            "unit_price": 150000,
                        }
                    ],
                },
                headers={"X-Requested-With": "XMLHttpRequest"},
            )

        self.assertEqual(checkout.status_code, 200)
        payload = checkout.get_json()
        self.assertEqual(payload["status"], "success")
        self.assertEqual(payload["receipt_whatsapp_status"], "sent")
        mocked_document.assert_called_once()
        mocked_text.assert_called_once()
        fallback_message = mocked_text.call_args.args[1]
        self.assertIn("Jika file PDF belum muncul otomatis", fallback_message)
