    def test_finished_career_assessment_cannot_be_submitted_again(self):
        with self.app.app_context():
            db = get_db()
            ensure_career_schema(db)
            db.execute(
                """
                INSERT INTO recruitment_assessment_questions(
                    warehouse_id, prompt, option_a, option_b, option_c, option_d, correct_option, score_weight, sort_order, is_active
                )
                VALUES (?,?,?,?,?,?,?,?,?,?)
                """,
                (1, "2 + 2 =", "3", "4", "5", "6", "b", 50, 1, 1),
            )
            db.execute(
                """
                INSERT INTO recruitment_assessment_questions(
                    warehouse_id, prompt, option_a, option_b, option_c, option_d, correct_option, score_weight, sort_order, is_active
                )
                VALUES (?,?,?,?,?,?,?,?,?,?)
                """,
                (1, "Huruf setelah A", "C", "D", "B", "E", "c", 50, 2, 1),
            )
            db.execute(
                """
                INSERT INTO recruitment_candidates(
                    candidate_name, warehouse_id, position_title, department, stage, status, source,
                    assessment_code, assessment_status, application_channel, updated_at
                )
                VALUES (?,?,?,?,?,?,?,?,?,?,CURRENT_TIMESTAMP)
                """,
                (
                    "Locked Candidate",
                    1,
                    "Staff Karir Locked",
                    "Warehouse",
                    "screening",
                    "active",
                    "Halaman Karir",
                    "56789",
                    "pending",
                    "public_portal",
                ),
            )
            db.commit()
            candidate = db.execute(
                """
                SELECT id, assessment_code
                FROM recruitment_candidates
                WHERE candidate_name=?
                ORDER BY id DESC
                LIMIT 1
                """,
                ("Locked Candidate",),
            ).fetchone()
        self.assertIsNotNone(candidate)

        first_submit = self.client.post(
            "/karir/tes/submit",
            data={
                "assessment_code": candidate["assessment_code"],
                "answer_1": "b",
                "answer_2": "a",
                "violation_count": "0",
            },
            follow_redirects=False,
        )
        self.assertEqual(first_submit.status_code, 302)

        with self.app.app_context():
            db = get_db()
            before_retry = db.execute(
                """
                SELECT assessment_status, assessment_answers_json, assessment_auto_score, assessment_final_score
                FROM recruitment_candidates
                WHERE id=?
                """,
                (candidate["id"],),
            ).fetchone()

        retry_submit = self.client.post(
            "/karir/tes/submit",
            data={
                "assessment_code": candidate["assessment_code"],
                "answer_1": "a",
                "answer_2": "c",
                "violation_count": "0",
            },
            follow_redirects=False,
        )
        self.assertEqual(retry_submit.status_code, 302)
        self.assertTrue(retry_submit.headers["Location"].endswith(f"/karir/tes?code={candidate['assessment_code']}"))

        with self.app.app_context():
            db = get_db()
            after_retry = db.execute(
                """
                SELECT assessment_status, assessment_answers_json, assessment_auto_score, assessment_final_score
                FROM recruitment_candidates
                WHERE id=?
                """,
                (candidate["id"],),
            ).fetchone()

        self.assertEqual(after_retry["assessment_status"], "submitted")
        self.assertEqual(after_retry["assessment_answers_json"], before_retry["assessment_answers_json"])
        self.assertEqual(float(after_retry["assessment_auto_score"]), float(before_retry["assessment_auto_score"]))
        self.assertEqual(float(after_retry["assessment_final_score"]), float(before_retry["assessment_final_score"]))

    def test_career_schema_repairs_missing_postgresql_id_defaults(self):
        with self.app.app_context():
            db = Mock()
            default_rows = {
                "career_openings": {"column_default": None},
                "recruitment_candidates": {"column_default": None},
                "recruitment_assessment_questions": {"column_default": None},
                "career_public_account_requests": {"column_default": None},
            }

            def execute_side_effect(query, parameters=None):
                normalized = " ".join(str(query).split()).lower()
                if "information_schema.columns" in normalized:
                    table_name = parameters[0]
                    return Mock(fetchone=Mock(return_value=default_rows.get(table_name)))
                return Mock(fetchone=Mock(return_value=None), fetchall=Mock(return_value=[]))

            db.execute.side_effect = execute_side_effect

            with patch("services.career_service.is_postgresql_backend", return_value=True):
                ensure_career_schema(db)

            executed_queries = [str(call.args[0]) for call in db.execute.call_args_list]
            self.assertTrue(any("career_openings_id_seq" in query for query in executed_queries))
            self.assertTrue(any("recruitment_candidates_id_seq" in query for query in executed_queries))
            self.assertTrue(any("recruitment_assessment_questions_id_seq" in query for query in executed_queries))
            self.assertTrue(any("career_public_account_requests_id_seq" in query for query in executed_queries))

