    def test_delete_all_products_cleans_related_so_and_ipos_mapping_rows(self):
        self.create_user("leader_delete_all_related", "pass1234", "leader", warehouse_id=1)

        with self.app.app_context():
            db = get_db()
            product_id = db.execute(
                """
                INSERT INTO products(sku, name, category_id, unit_label, variant_mode)
                VALUES (?,?,?,?,?)
                """,
                ("DEL-ALL-REL-001", "Produk Relasi", None, "pcs", "non_variant"),
            ).lastrowid
            variant_id = db.execute(
                """
                INSERT INTO product_variants(product_id, variant, price_retail, price_discount, price_nett, variant_code, color, gtin, no_gtin)
                VALUES (?,?,?,?,?,'','','',1)
                """,
                (product_id, "default", 0, 0, 0),
            ).lastrowid
            db.execute(
                "INSERT INTO stock(product_id, variant_id, warehouse_id, qty) VALUES (?,?,?,?)",
                (product_id, variant_id, 1, 3),
            )
            db.execute(
                """
                INSERT INTO stock_opname_results(product_id, variant_id, warehouse_id, area_kind, system_qty, physical_qty, diff_qty, user_id)
                VALUES (?,?,?,?,?,?,?,NULL)
                """,
                (product_id, variant_id, 1, "display", 0, 1, 1),
            )
            db.execute(
                """
                INSERT INTO stock_area_balances(product_id, variant_id, warehouse_id, area_kind, qty, updated_by)
                VALUES (?,?,?,?,?,NULL)
                """,
                (product_id, variant_id, 1, "display", 1),
            )
            db.execute(
                """
                CREATE TABLE IF NOT EXISTS ipos_import_product_map(
                    source_item_code TEXT PRIMARY KEY,
                    source_item_name TEXT,
                    product_id INTEGER NOT NULL,
                    source_dump TEXT,
                    synced_at TEXT NOT NULL,
                    FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE
                )
                """
            )
            db.execute(
                """
                INSERT INTO ipos_import_product_map(source_item_code, source_item_name, product_id, source_dump, synced_at)
                VALUES (?,?,?,?,datetime('now'))
                """,
                ("REL-001", "Produk Relasi", product_id, "/tmp/dump.i4bu"),
            )
            db.commit()

        self.login("leader_delete_all_related", "pass1234")
        response = self.client.post(
            "/products/delete-all",
            json={"confirmation_text": "HAPUS SEMUA PRODUK"},
            follow_redirects=False,
        )

        self.assertEqual(response.status_code, 200)
        payload = response.get_json()
        self.assertEqual(payload["status"], "success")
        self.assertEqual(payload["deleted_count"], 1)

        with self.app.app_context():
            db = get_db()
            product_count = db.execute(
                "SELECT COUNT(*) FROM products WHERE id=?",
                (product_id,),
            ).fetchone()[0]
            so_count = db.execute(
                "SELECT COUNT(*) FROM stock_opname_results WHERE product_id=?",
                (product_id,),
            ).fetchone()[0]
            area_count = db.execute(
                "SELECT COUNT(*) FROM stock_area_balances WHERE product_id=?",
                (product_id,),
            ).fetchone()[0]
            map_count = db.execute(
                "SELECT COUNT(*) FROM ipos_import_product_map WHERE product_id=?",
                (product_id,),
            ).fetchone()[0]

        self.assertEqual(product_count, 0)
        self.assertEqual(so_count, 0)
        self.assertEqual(area_count, 0)
        self.assertEqual(map_count, 0)

    def test_owner_can_update_owner_request_status_and_notify_requester(self):
        self.create_user("owner_manager", "pass1234", "owner")
        self.login()
        response, product_id, variants_rows = self.create_product(qty=10, variants="41")
        self.assertEqual(response.status_code, 302)

        with self.app.app_context():
            db = get_db()
            db.execute(
                """
                UPDATE users
                SET email=?, notify_email=1
                WHERE username=?
                """,
                ("admin_notify@example.com", "admin"),
            )
            db.commit()

        request_response = self.client.post(
            "/request/owner",
            data={
                "warehouse_id": "1",
                "items_json": json.dumps([
                    {
                        "product_id": product_id,
                        "variant_id": variants_rows[0]["id"],
                        "qty": 2,
                        "note": "Owner approval needed",
                    },
                ]),
            },
            follow_redirects=False,
        )
        self.assertEqual(request_response.status_code, 302)

        with self.app.app_context():
            db = get_db()
            owner_request = db.execute(
                """
                SELECT id, requested_by, status
                FROM owner_requests
                WHERE product_id=?
                ORDER BY id DESC
                LIMIT 1
                """,
                (product_id,),
            ).fetchone()

        self.assertEqual(owner_request["status"], "pending")

        self.logout()
        self.login("owner_manager", "pass1234")

        owner_queue = self.client.get("/request/owner")
        self.assertEqual(owner_queue.status_code, 200)
        self.assertIn("Proses", owner_queue.get_data(as_text=True))

        update_response = self.client.post(
            f"/request/owner/update/{owner_request['id']}",
            data={"status": "in_progress"},
            follow_redirects=False,
        )
        self.assertEqual(update_response.status_code, 302)

        with self.app.app_context():
            db = get_db()
            owner_request_after = db.execute(
                "SELECT status, handled_by FROM owner_requests WHERE id=?",
                (owner_request["id"],),
            ).fetchone()
            requester_notification = db.execute(
                """
                SELECT recipient, subject, status
                FROM notifications
                WHERE recipient=?
                  AND subject LIKE ?
                ORDER BY id DESC
                LIMIT 1
                """,
                ("admin_notify@example.com", f"Request ke owner #{owner_request['id']}%"),
            ).fetchone()

        self.assertEqual(owner_request_after["status"], "in_progress")
        self.assertIsNotNone(owner_request_after["handled_by"])
        self.assertIsNotNone(requester_notification)
        self.assertIn("Diproses", requester_notification["subject"])

    def test_leader_can_process_bulk_transfer_directly(self):
        self.create_user("leader_transfer", "pass1234", "leader", warehouse_id=1)
        self.login()
        response, product_id, variants_rows = self.create_product(qty=10, variants="41,42")
        self.assertEqual(response.status_code, 302)
        self.logout()

        self.login("leader_transfer", "pass1234")
        transfer_response = self.client.post(
            "/transfers/",
            data={
                "from_warehouse": "1",
                "to_warehouse": "2",
                "items_json": json.dumps([
                    {
                        "product_id": product_id,
                        "variant_id": variants_rows[0]["id"],
                        "qty": 2,
                    },
                    {
                        "product_id": product_id,
                        "variant_id": variants_rows[1]["id"],
                        "qty": 3,
                    },
                ]),
            },
            follow_redirects=False,
        )
        self.assertEqual(transfer_response.status_code, 302)

        with self.app.app_context():
            db = get_db()
            stock_from = db.execute(
                """
                SELECT variant_id, qty
                FROM stock
                WHERE product_id=? AND warehouse_id=1
                ORDER BY variant_id
                """,
                (product_id,),
            ).fetchall()
            stock_to = db.execute(
                """
                SELECT variant_id, qty
                FROM stock
                WHERE product_id=? AND warehouse_id=2
                ORDER BY variant_id
                """,
                (product_id,),
            ).fetchall()
            request_rows = db.execute(
                """
                SELECT variant_id, qty, status
                FROM requests
                WHERE product_id=?
                ORDER BY variant_id
                """,
                (product_id,),
            ).fetchall()

        self.assertEqual(len(stock_from), 2)
        self.assertEqual(stock_from[0]["qty"], 8)
        self.assertEqual(stock_from[1]["qty"], 7)
        self.assertEqual(len(stock_to), 2)
        self.assertEqual(stock_to[0]["qty"], 2)
        self.assertEqual(stock_to[1]["qty"], 3)
        self.assertEqual(len(request_rows), 2)
        self.assertEqual(request_rows[0]["status"], "approved")
        self.assertEqual(request_rows[1]["status"], "approved")

