    def test_forgot_password_invalidates_previous_reset_codes(self):
        self.create_user(
            "reset_rotate",
            "pass1234",
            "admin",
            warehouse_id=1,
            email="rotate@example.test",
            notify_email=1,
        )

        first = self.client.post(
            "/forgot",
            data={"identifier": "rotate@example.test"},
            follow_redirects=False,
        )
        second = self.client.post(
            "/forgot",
            data={"identifier": "rotate@example.test"},
            follow_redirects=False,
        )

        self.assertEqual(first.status_code, 302)
        self.assertEqual(second.status_code, 302)

        with self.app.app_context():
            db = get_db()
            rows = db.execute(
                """
                SELECT pr.code, pr.used
                FROM password_resets pr
                JOIN users u ON u.id = pr.user_id
                WHERE u.username=?
                ORDER BY pr.id DESC
                """,
                ("reset_rotate",),
            ).fetchall()

        self.assertGreaterEqual(len(rows), 2)
        self.assertEqual(rows[0]["used"], 0)
        self.assertEqual(rows[1]["used"], 1)

    def test_reset_password_enforces_minimum_length(self):
        self.create_user(
            "reset_policy",
            "pass1234",
            "admin",
            warehouse_id=1,
            email="policy@example.test",
            notify_email=1,
        )

        self.client.post(
            "/forgot",
            data={"identifier": "policy@example.test"},
            follow_redirects=False,
        )

        with self.app.app_context():
            db = get_db()
            code = db.execute(
                """
                SELECT pr.code
                FROM password_resets pr
                JOIN users u ON u.id = pr.user_id
                WHERE u.username=?
                ORDER BY pr.id DESC
                LIMIT 1
                """,
                ("reset_policy",),
            ).fetchone()["code"]

        short_reset = self.client.post(
            "/reset",
            data={
                "username": "reset_policy",
                "code": code,
                "password": "123",
            },
            follow_redirects=True,
        )
        self.assertEqual(short_reset.status_code, 200)
        self.assertIn("Password minimal 8 karakter", short_reset.get_data(as_text=True))

        bad_login = self.login("reset_policy", "123")
        self.assertEqual(bad_login.status_code, 302)
        good_login = self.login("reset_policy", "pass1234")
        self.assertEqual(good_login.status_code, 302)

    def test_login_rate_limit_blocks_repeated_failures(self):
        self.create_user("throttle_user", "pass1234", "admin", warehouse_id=1)

        for _ in range(3):
            response = self.client.post(
                "/login",
                data={"username": "throttle_user", "password": "salah"},
                follow_redirects=False,
            )
            self.assertEqual(response.status_code, 302)

        blocked = self.client.post(
            "/login",
            data={"username": "throttle_user", "password": "pass1234"},
            follow_redirects=True,
        )
        self.assertEqual(blocked.status_code, 200)
        self.assertIn("Terlalu banyak percobaan login", blocked.get_data(as_text=True))

        with self.client.session_transaction() as sess:
            self.assertIsNone(sess.get("user_id"))

        with self.app.app_context():
            db = get_db()
            attempts = db.execute(
                """
                SELECT COUNT(*)
                FROM login_attempts
                WHERE identifier=?
                """,
                ("throttle_user",),
            ).fetchone()[0]

        self.assertEqual(attempts, 3)

    def test_send_whatsapp_marks_http_failure(self):
        if notification_service.http_requests is None:
            self.skipTest("requests library unavailable")

        class FakeResponse:
            ok = False
            status_code = 500
            headers = {"Content-Type": "application/json"}

            @staticmethod
            def json():
                return {"status": False}

        with patch.dict(os.environ, {"FONNTE_API_KEY": "test-key"}, clear=False):
            with patch.object(notification_service.http_requests, "post", return_value=FakeResponse()):
                result = notification_service.send_whatsapp("628123456789", "Halo")

        self.assertFalse(result)

    def test_send_email_uses_brevo_sender_override_when_configured(self):
        fake_server = Mock()

        with patch.dict(
            os.environ,
            {
                "SMTP_HOST": "smtp-relay.brevo.com",
                "SMTP_PORT": "587",
                "SMTP_USER": "smtp-login@example.com",
                "SMTP_PASS": "smtp-secret",
                "SMTP_TLS": "1",
                "SMTP_SSL": "0",
                "SMTP_FROM_EMAIL": "career@cvbjasyogya.cloud",
                "SMTP_FROM_NAME": "CV Berkah Jaya Abadi Sports Career",
            },
            clear=False,
        ):
            with patch("services.notification_service.smtplib.SMTP", return_value=fake_server):
                result = notification_service.send_email(
                    "candidate@example.com",
                    "Tes Brevo",
                    "Halo kandidat",
                )

        self.assertTrue(result)
        fake_server.login.assert_called_once_with("smtp-login@example.com", "smtp-secret")
        sent_message = fake_server.send_message.call_args.args[0]
        self.assertEqual(sent_message["From"], "CV Berkah Jaya Abadi Sports Career <career@cvbjasyogya.cloud>")
        self.assertEqual(sent_message["To"], "candidate@example.com")
        self.assertEqual(sent_message["Subject"], "Tes Brevo")

