    def test_role_refresh_allows_promoted_user_to_adjust_directly(self):
        self.create_user("Rio", "admin123", "admin", warehouse_id=1)
        self.login("Rio", "admin123")
        _, product_id, variants_rows = self.create_product(variants="RIO")
        variant_id = variants_rows[0]["id"]

        with self.app.app_context():
            db = get_db()
            db.execute(
                "UPDATE users SET role=? WHERE username=?",
                ("super_admin", "Rio"),
            )
            db.commit()

        stock_page = self.client.get("/stock/", follow_redirects=False)
        self.assertEqual(stock_page.status_code, 200)

        with self.client.session_transaction() as sess:
            self.assertEqual(sess.get("role"), "super_admin")

        adjust_response = self.client.post(
            "/stock/adjust",
            data={
                "product_id": str(product_id),
                "variant_id": str(variant_id),
                "warehouse_id": "1",
                "qty": "-2",
            },
            headers={"X-Requested-With": "XMLHttpRequest"},
            follow_redirects=False,
        )
        self.assertEqual(adjust_response.status_code, 200)
        self.assertEqual(adjust_response.get_json()["status"], "success")

        with self.app.app_context():
            db = get_db()
            approvals = db.execute(
                "SELECT COUNT(*) FROM approvals WHERE product_id=?",
                (product_id,),
            ).fetchone()[0]
            stock_after = db.execute(
                "SELECT qty FROM stock WHERE product_id=? AND variant_id=? AND warehouse_id=1",
                (product_id, variant_id),
            ).fetchone()

        self.assertEqual(approvals, 0)
        self.assertEqual(stock_after["qty"], 3)

    def test_stock_opname_submit_updates_stock_and_history(self):
        self.login()
        _, product_id, variants_rows = self.create_product(qty=9, variants="SO")
        variant_id = variants_rows[0]["id"]

        response = self.client.post(
            "/so/submit",
            json={
                "warehouse_id": 1,
                "items": [
                    {
                        "product_id": product_id,
                        "variant_id": variant_id,
                        "display_system": 0,
                        "display_physical": 1,
                        "gudang_system": 9,
                        "gudang_physical": 10,
                    }
                ],
            },
            follow_redirects=False,
        )
        self.assertEqual(response.status_code, 200)

        with self.app.app_context():
            db = get_db()
            store_stock = db.execute(
                "SELECT qty FROM stock WHERE product_id=? AND variant_id=? AND warehouse_id=1",
                (product_id, variant_id),
            ).fetchone()
            display_area = db.execute(
                """
                SELECT qty FROM stock_area_balances
                WHERE product_id=? AND variant_id=? AND warehouse_id=1 AND area_kind='display'
                """,
                (product_id, variant_id),
            ).fetchone()
            gudang_area = db.execute(
                """
                SELECT qty FROM stock_area_balances
                WHERE product_id=? AND variant_id=? AND warehouse_id=1 AND area_kind='gudang'
                """,
                (product_id, variant_id),
            ).fetchone()
            so_rows = db.execute(
                """
                SELECT COUNT(*) FROM stock_opname_results
                WHERE product_id=? AND variant_id=? AND warehouse_id=1
                """,
                (product_id, variant_id),
            ).fetchone()[0]
            history_rows = db.execute(
                """
                SELECT COUNT(*) FROM stock_history
                WHERE product_id=? AND variant_id=? AND warehouse_id=1 AND action='STOCK_OPNAME'
                """,
                (product_id, variant_id),
            ).fetchone()[0]

        self.assertEqual(store_stock["qty"], 11)
        self.assertEqual(display_area["qty"], 1)
        self.assertEqual(gudang_area["qty"], 10)
        self.assertEqual(so_rows, 2)
        self.assertEqual(history_rows, 1)

    def test_stock_opname_submit_keeps_batch_history_when_batches_are_referenced(self):
        self.login()
        _, product_id, variants_rows = self.create_product(qty=9, variants="SOBATCHFK")
        variant_id = variants_rows[0]["id"]

        with self.app.app_context():
            db = get_db()
            batch_row = db.execute(
                """
                SELECT id, remaining_qty
                FROM stock_batches
                WHERE product_id=? AND variant_id=? AND warehouse_id=1
                ORDER BY id ASC
                LIMIT 1
                """,
                (product_id, variant_id),
            ).fetchone()
            self.assertIsNotNone(batch_row)
            movement_count_before = db.execute(
                """
                SELECT COUNT(*) FROM stock_movements
                WHERE batch_id=?
                """,
                (batch_row["id"],),
            ).fetchone()[0]
            db.execute(
                """
                INSERT INTO stock_movements(product_id, variant_id, warehouse_id, batch_id, qty, type)
                VALUES (?,?,?,?,?,?)
                """,
                (product_id, variant_id, 1, batch_row["id"], 1, "IN"),
            )
            db.commit()

        response = self.client.post(
            "/so/submit",
            json={
                "warehouse_id": 1,
                "items": [
                    {
                        "product_id": product_id,
                        "variant_id": variant_id,
                        "display_physical": 1,
                        "gudang_physical": 7,
                    }
                ],
            },
            follow_redirects=False,
        )
        self.assertEqual(response.status_code, 200)

        with self.app.app_context():
            db = get_db()
            old_batch = db.execute(
                """
                SELECT remaining_qty
                FROM stock_batches
                WHERE id=?
                """,
                (batch_row["id"],),
            ).fetchone()
            movement_count = db.execute(
                """
                SELECT COUNT(*) FROM stock_movements
                WHERE batch_id=?
                """,
                (batch_row["id"],),
            ).fetchone()[0]
            total_batch_qty = db.execute(
                """
                SELECT COALESCE(SUM(remaining_qty), 0)
                FROM stock_batches
                WHERE product_id=? AND variant_id=? AND warehouse_id=1
                """,
                (product_id, variant_id),
            ).fetchone()[0]
            stock_row = db.execute(
                "SELECT qty FROM stock WHERE product_id=? AND variant_id=? AND warehouse_id=1",
                (product_id, variant_id),
            ).fetchone()

        self.assertEqual(old_batch["remaining_qty"], 0)
        self.assertEqual(movement_count, movement_count_before + 1)
        self.assertEqual(total_batch_qty, 8)
        self.assertEqual(stock_row["qty"], 8)

    def test_stock_opname_submit_updates_multiple_products_in_one_request(self):
        self.login()
        payload_items = []
        created_rows = []

        for idx, qty in enumerate((5, 6, 7), start=1):
            response, product_id, variants_rows = self.create_product(
                sku=f"SO-BULK-{idx}",
                qty=qty,
                variants=f"SO{idx}",
                name=f"Produk Bulk {idx}",
            )
            self.assertEqual(response.status_code, 302)
            variant_id = variants_rows[0]["id"]
            created_rows.append((product_id, variant_id, qty, idx))
            payload_items.append(
                {
                    "product_id": product_id,
                    "variant_id": variant_id,
                    "display_physical": idx,
                    "gudang_physical": qty + 1,
                }
            )

        response = self.client.post(
            "/so/submit",
            json={
                "warehouse_id": 1,
                "items": payload_items,
            },
            follow_redirects=False,
        )
        self.assertEqual(response.status_code, 200)
        payload = response.get_json()
        self.assertEqual(payload["processed"], 3)

        with self.app.app_context():
            db = get_db()
            for product_id, variant_id, qty, idx in created_rows:
                stock_row = db.execute(
                    "SELECT qty FROM stock WHERE product_id=? AND variant_id=? AND warehouse_id=1",
                    (product_id, variant_id),
                ).fetchone()
                result_rows = db.execute(
                    """
                    SELECT COUNT(*) FROM stock_opname_results
                    WHERE product_id=? AND variant_id=? AND warehouse_id=1
                    """,
                    (product_id, variant_id),
                ).fetchone()[0]
                history_rows = db.execute(
                    """
                    SELECT COUNT(*) FROM stock_history
                    WHERE product_id=? AND variant_id=? AND warehouse_id=1 AND action='STOCK_OPNAME'
                    """,
                    (product_id, variant_id),
                ).fetchone()[0]

                self.assertEqual(stock_row["qty"], qty + idx + 1)
                self.assertEqual(result_rows, 2)
                self.assertEqual(history_rows, 1)

